            compose.onNode(hasText(connectionSection) and hasStateDescription(collapsedState))
                .performScrollTo()
                .performClick()
            compose.waitForIdle()

            compose.onNode(
                hasContentDescription(expectedActionLabel) and
                    hasClickActionLabel(expectedActionLabel),
                useUnmergedTree = true,
            )
                .performScrollTo()
                .assertIsDisplayed()
                .assertIsEnabled()
                .performClick()
            compose.waitForIdle()

            compose.onNodeWithContentDescription(expectedConfirmMessage, useUnmergedTree = true)
                .assertExists()
            compose.onNode(
                hasContentDescription(expectedConfirmActionLabel) and
                    hasClickActionLabel(expectedConfirmActionLabel),
                useUnmergedTree = true,
            )
                .assertIsDisplayed()
                .assertIsEnabled()
            compose.onNode(
