                hasStateDescription(connectingState) and
                    hasClickActionLabel(disconnectAction),
            )
                .assertIsDisplayed()
                .assertIsNotEnabled()
        }

        assertEquals(0, refreshClicks)
        assertEquals(0, disconnectClicks)
    }

