    @Test
    fun settingsScreenKeepsEndpointInputsBehindDeveloperDiagnosticsSwitch() {
        compose.setContent {
            MaterialTheme {
                SettingsScreen(
                    state = RuntimeUiState(),
                    onHostChange = {},
                    onPortChange = {},
                    onUseUsbReverse = {},
                    onUseEmulator = {},
