        compose.onNodeWithText("Emulator connection").assertIsDisplayed()
        compose.onNodeWithText("Connection address").assertIsDisplayed()
        compose.onNodeWithText("Connection port").assertIsDisplayed()
    }

    @Test
    fun diagnosticQrTextDialogExplainsEmptyInvalidAndReadyStates() {
        val submittedPayloads = mutableListOf<String>()
        val invalidPayload = "https://example.test/pair?pairing_code=123456"
        val validPayload = "aetherlink://pair?version=1&pairing_nonce=nonce-1&pairing_code=123456" +
            "&runtime_device_id=runtime-1&runtime_key_fingerprint=fingerprint-1"

        compose.setContent {
            MaterialTheme {
                SettingsScreen(
                    state = RuntimeUiState(),
                    onHostChange = {},
                    onPortChange = {},
                    onUseUsbReverse = {},
                    onUseEmulator = {},
                    onStartDiscovery = {},
                    onStopDiscovery = {},
                    onUseDiscoveredRuntime = {},
                    onForgetTrustedRuntime = {},
                    onScanPairingQr = {},
                    onSubmitPairingPayload = { submittedPayloads += it },
                    onConnect = {},
                    onRefreshHealth = {},
                    onRequestModels = {},
                    onDisconnect = {},
                    onSetAutoReconnectEnabled = {},
                    onSetLanguageTag = {},
                    onSetTheme = {},
                    onSelectEmbeddingModel = {},
                    onAddMemoryEntry = {},
                    onRemoveMemoryEntry = {},
                    onSetMemoryEntryEnabled = { _, _ -> },
                    onArchiveChatSession = {},
                    onRestoreChatSession = {},
                    onPermanentlyDeleteChatSession = {},
                    onArchiveAllChatSessions = {},
                    onPermanentlyDeleteArchivedChatSessions = {},
                    showDeveloperDiagnostics = true,
                )
            }
        }

        repeat(2) {
            compose.onRoot().performTouchInput { swipeUp() }
            compose.waitForIdle()
        }
        compose.onNodeWithText("Troubleshooting")
            .assertIsDisplayed()
            .performClick()
        compose.onNodeWithTag(DEVELOPER_DIAGNOSTICS_TOGGLE_ROW_TAG).performClick()
        compose.waitForIdle()
        compose.onNode(
            hasText("Diagnostic QR text") and
                hasContentDescription("Open diagnostic QR text") and
                hasClickActionLabel("Open diagnostic QR text"),
        )
            .performScrollTo()
            .assertIsDisplayed()
            .performClick()

        compose.onNode(
            hasSetTextAction() and
                hasContentDescription("Diagnostic QR text input") and
                hasStateDescription("Paste AetherLink Runtime QR text before continuing."),
        )
            .assertIsDisplayed()
        compose.onNode(
            hasText("Use QR text") and
                hasContentDescription("Use diagnostic QR text") and
                hasClickActionLabel("Use diagnostic QR text") and
                hasStateDescription("Paste AetherLink Runtime QR text before continuing."),
        )
            .assertIsNotEnabled()
        compose.onNode(
            hasText("Cancel") and
                hasContentDescription("Close diagnostic QR text") and
                hasClickActionLabel("Close diagnostic QR text"),
        ).assertIsDisplayed()

        compose.onNode(hasSetTextAction())
            .performTextInput(invalidPayload)
        compose.waitForIdle()
        compose.onNodeWithText("Use AetherLink Runtime QR text that starts with aetherlink://pair.")
            .assertIsDisplayed()
        compose.onNode(
            hasText("Use QR text") and
                hasContentDescription("Use diagnostic QR text") and
                hasClickActionLabel("Use diagnostic QR text") and
                hasStateDescription("Use AetherLink Runtime QR text that starts with aetherlink://pair."),
        )
            .assertIsNotEnabled()

        compose.onNode(hasSetTextAction())
            .performTextClearance()
        compose.onNode(hasSetTextAction())
            .performTextInput(validPayload)
        compose.waitForIdle()
        compose.onNodeWithText("Ready to use QR text.")
            .assertIsDisplayed()
        compose.onNode(
            hasText("Use QR text") and
                hasContentDescription("Use diagnostic QR text") and
                hasClickActionLabel("Use diagnostic QR text") and
                hasStateDescription("Ready to use QR text."),
        )
            .assertIsEnabled()
            .performClick()

        assertEquals(listOf(validPayload), submittedPayloads)
    }

    @Test
    fun diagnosticQrTextAccessibilityLabelsLocalizeAcrossSupportedLanguages() {
        data class ExpectedDiagnosticQrAccessibility(
            val languageTag: String,
            val open: String,
            val input: String,
            val submit: String,
            val cancel: String,
        )

        val expectations = listOf(
            ExpectedDiagnosticQrAccessibility(
                languageTag = "en",
                open = "Open diagnostic QR text",
                input = "Diagnostic QR text input",
                submit = "Use diagnostic QR text",
                cancel = "Close diagnostic QR text",
            ),
            ExpectedDiagnosticQrAccessibility(
                languageTag = "ko",
                open = "진단용 QR 텍스트 열기",
                input = "진단용 QR 텍스트 입력",
                submit = "진단용 QR 텍스트 사용",
                cancel = "진단용 QR 텍스트 닫기",
            ),
            ExpectedDiagnosticQrAccessibility(
                languageTag = "ja",
                open = "診断用 QR テキストを開く",
                input = "診断用 QR テキスト入力",
                submit = "診断用 QR テキストを使用",
                cancel = "診断用 QR テキストを閉じる",
            ),
            ExpectedDiagnosticQrAccessibility(
                languageTag = "zh-CN",
                open = "打开诊断二维码文本",
                input = "诊断二维码文本输入",
                submit = "使用诊断二维码文本",
                cancel = "关闭诊断二维码文本",
            ),
            ExpectedDiagnosticQrAccessibility(
                languageTag = "fr",
                open = "Ouvrir le texte QR de diagnostic",
                input = "Saisie du texte QR de diagnostic",
                submit = "Utiliser le texte QR de diagnostic",
                cancel = "Fermer le texte QR de diagnostic",
            ),
        )

        expectations.forEach { expected ->
            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(expected.languageTag)

            assertEquals(
                "${expected.languageTag} diagnostic QR open accessibility",
                expected.open,
                localizedContext.getString(R.string.manual_qr_payload_open_accessibility),
            )
            assertEquals(
                "${expected.languageTag} diagnostic QR input accessibility",
                expected.input,
                localizedContext.getString(R.string.manual_qr_payload_input_accessibility),
            )
            assertEquals(
                "${expected.languageTag} diagnostic QR submit accessibility",
                expected.submit,
                localizedContext.getString(R.string.manual_qr_payload_submit_accessibility),
            )
            assertEquals(
                "${expected.languageTag} diagnostic QR cancel accessibility",
                expected.cancel,
                localizedContext.getString(R.string.manual_qr_payload_cancel_accessibility),
            )
        }
    }

    @Test
    fun diagnosticQrTextDialogStaysBoundedAtLargeFontAcrossSupportedLanguages() {
        data class ExpectedDiagnosticQrDialog(
            val languageTag: String,
            val inputLabel: String,
            val submitLabel: String,
            val cancelLabel: String,
            val invalidState: String,
        )

        val languageTags = listOf("en", "ko", "ja", "zh-CN", "fr")
        val expectations = languageTags.map { languageTag ->
            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag)
            ExpectedDiagnosticQrDialog(
                languageTag = languageTag,
                inputLabel = localizedContext.getString(R.string.manual_qr_payload_input_accessibility),
                submitLabel = localizedContext.getString(R.string.manual_qr_payload_submit_accessibility),
                cancelLabel = localizedContext.getString(R.string.manual_qr_payload_cancel_accessibility),
                invalidState = localizedContext.getString(R.string.manual_qr_payload_state_invalid),
            )
        }
        val currentLanguageTag = mutableStateOf(expectations.first().languageTag)
        val invalidPayload = "https://example.test/pair?pairing_code=123456"

        compose.setContent {
            MaterialTheme {
                LocalizedTestContent(languageTag = currentLanguageTag.value, fontScale = 1.45f) {
                    ManualPairingPayloadDialog(
                        onDismiss = {},
                        onSubmit = {},
                    )
                }
            }
        }

        expectations.forEach { expected ->
            currentLanguageTag.value = expected.languageTag
            compose.waitForIdle()

            compose.onNodeWithTag(MANUAL_QR_PAYLOAD_INPUT_TEST_TAG, useUnmergedTree = true)
                .performTextClearance()
            compose.onNodeWithTag(MANUAL_QR_PAYLOAD_INPUT_TEST_TAG, useUnmergedTree = true)
                .performTextInput(invalidPayload)
            compose.waitForIdle()

            val dialogBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_DIALOG_TEST_TAG, useUnmergedTree = true)
                .getUnclippedBoundsInRoot()
            val titleBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_TITLE_TEST_TAG, useUnmergedTree = true)
                .getUnclippedBoundsInRoot()
            val detailBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_DETAIL_TEST_TAG, useUnmergedTree = true)
                .getUnclippedBoundsInRoot()
            val inputBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_INPUT_TEST_TAG, useUnmergedTree = true)
                .assert(hasContentDescription(expected.inputLabel))
                .assert(hasStateDescription(expected.invalidState))
                .getUnclippedBoundsInRoot()
            val stateBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_STATE_TEST_TAG, useUnmergedTree = true)
                .getUnclippedBoundsInRoot()
            val submitBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_SUBMIT_TEST_TAG, useUnmergedTree = true)
                .assert(hasContentDescription(expected.submitLabel))
                .assert(hasStateDescription(expected.invalidState))
                .assert(hasClickActionLabel(expected.submitLabel))
                .getUnclippedBoundsInRoot()
            val cancelBounds = compose
                .onNodeWithTag(MANUAL_QR_PAYLOAD_CANCEL_TEST_TAG, useUnmergedTree = true)
                .assert(hasContentDescription(expected.cancelLabel))
                .assert(hasClickActionLabel(expected.cancelLabel))
                .getUnclippedBoundsInRoot()

            listOf(
                "dialog title" to titleBounds,
                "dialog detail" to detailBounds,
                "dialog input" to inputBounds,
                "dialog state" to stateBounds,
                "dialog submit action" to submitBounds,
                "dialog cancel action" to cancelBounds,
            ).forEach { (label, bounds) ->
                assertBoundsInside("${expected.languageTag} diagnostic QR text $label", bounds, dialogBounds)
            }
            assertBoundsInside(
                "${expected.languageTag} diagnostic QR text state helper",
                stateBounds,
                inputBounds,
            )
            assertFalse(
                "${expected.languageTag} diagnostic QR title should not overlap detail.",
                boundsOverlap(titleBounds, detailBounds),
            )
            assertFalse(
                "${expected.languageTag} diagnostic QR detail should not overlap input.",
                boundsOverlap(detailBounds, inputBounds),
            )
            assertFalse(
                "${expected.languageTag} diagnostic QR actions should not overlap.",
                boundsOverlap(submitBounds, cancelBounds),
            )
        }
    }

