    @Test
    fun chatDrawerOverflowMenuActionsKeepChatContextAcrossSupportedLanguages() {
        data class ExpectedMenuCopy(
            val languageTag: String,
            val options: String,
            val rename: String,
            val archive: String,
            val restore: String,
            val delete: String,
        )

        val expectedCopies = listOf(
            ExpectedMenuCopy(
                languageTag = "en",
                options = "Chat options for Trip plan",
                rename = "Rename chat Trip plan",
                archive = "Archive chat Trip plan",
                restore = "Restore chat Trip plan",
                delete = "Delete chat Trip plan",
            ),
            ExpectedMenuCopy(
                languageTag = "ko",
                options = "Trip plan 채팅 옵션",
                rename = "Trip plan 채팅 이름 변경",
                archive = "Trip plan 채팅 보관",
                restore = "Trip plan 채팅 복원",
                delete = "Trip plan 채팅 삭제",
            ),
            ExpectedMenuCopy(
                languageTag = "ja",
                options = "「Trip plan」のチャットオプション",
                rename = "「Trip plan」の名前を変更",
                archive = "「Trip plan」をアーカイブ",
                restore = "「Trip plan」を復元",
                delete = "「Trip plan」を削除",
            ),
            ExpectedMenuCopy(
                languageTag = "zh-CN",
                options = "聊天“Trip plan”的选项",
                rename = "重命名聊天“Trip plan”",
                archive = "归档聊天“Trip plan”",
                restore = "恢复聊天“Trip plan”",
                delete = "删除聊天“Trip plan”",
            ),
            ExpectedMenuCopy(
                languageTag = "fr",
                options = "Options du chat « Trip plan »",
                rename = "Renommer le chat « Trip plan »",
                archive = "Archiver le chat « Trip plan »",
                restore = "Restaurer le chat « Trip plan »",
                delete = "Supprimer le chat « Trip plan »",
            ),
        )
        val currentCopy = mutableStateOf(expectedCopies.first())
        var renameClicks = 0
        var archiveClicks = 0
        var restoreClicks = 0
        var deleteClicks = 0

        compose.setContent {
            MaterialTheme {
                val expected = currentCopy.value
                LocalizedTestContent(languageTag = expected.languageTag) {
                    ChatSessionDrawerItem(
                        session = RuntimeChatSession(
                            id = "trip-chat",
                            title = "Trip plan",
                            updatedAtMillis = 2_000L,
                            messageCount = 4,
                        ),
                        selected = false,
                        enabled = true,
                        onClick = {},
                        onRename = { renameClicks += 1 },
                        onArchive = { archiveClicks += 1 },
                        onRestore = { restoreClicks += 1 },
                        onDelete = { deleteClicks += 1 },
                    )
                }
            }
        }

        expectedCopies.forEachIndexed { index, expected ->
            compose.runOnUiThread {
                currentCopy.value = expected
            }
            compose.waitForIdle()

            compose.onNodeWithContentDescription(expected.options, useUnmergedTree = true)
                .assertIsDisplayed()
                .assert(hasClickActionLabel(expected.options))
                .performClick()
            compose.waitForIdle()

            listOf(expected.rename, expected.archive, expected.restore, expected.delete).forEach { label ->
                compose.onNode(
                    hasContentDescription(label) and hasClickActionLabel(label),
                    useUnmergedTree = true,
                ).assertIsDisplayed()
            }

            compose.onNode(
                hasContentDescription(expected.rename) and hasClickActionLabel(expected.rename),
                useUnmergedTree = true,
            ).performClick()
            compose.waitForIdle()
            assertEquals(index + 1, renameClicks)
        }
        assertEquals(0, archiveClicks)
        assertEquals(0, restoreClicks)
        assertEquals(0, deleteClicks)
    }

    @Test
    fun chatDrawerOverflowMenuActionsStayBoundedAtLargeFontAcrossSupportedLanguages() {
        data class MenuActionExpectation(
            val action: String,
            val labelRes: Int,
            val namedLabelRes: Int,
        )

        val languageTags = listOf("en", "ko", "ja", "zh-CN", "fr")
        val menuActions = listOf(
            MenuActionExpectation(
                action = "rename",
                labelRes = R.string.rename_chat,
                namedLabelRes = R.string.rename_chat_named,
            ),
            MenuActionExpectation(
                action = "archive",
                labelRes = R.string.archive_chat,
                namedLabelRes = R.string.archive_chat_named,
            ),
            MenuActionExpectation(
                action = "restore",
                labelRes = R.string.restore_chat,
                namedLabelRes = R.string.restore_chat_named,
            ),
            MenuActionExpectation(
                action = "delete",
                labelRes = R.string.delete_chat,
                namedLabelRes = R.string.delete_chat_named,
            ),
        )
        val session = RuntimeChatSession(
            id = "compact-overflow-menu",
            title = "International roadmap planning session",
            updatedAtMillis = 2_000L,
            messageCount = 24,
            modelId = "ollama:very-long-local-model-name",
        )
        val currentLanguage = mutableStateOf(languageTags.first())

        compose.setContent {
            MaterialTheme {
                Surface(
                    modifier = Modifier
                        .width(300.dp)
                        .height(380.dp)
                        .testTag(chatDrawerOverflowMenuNarrowRootTestTag),
                ) {
                    LocalizedTestContent(languageTag = currentLanguage.value, fontScale = 1.45f) {
                        ChatSessionDrawerItem(
                            session = session,
                            models = listOf(
                                RuntimeModel(
                                    id = "ollama:very-long-local-model-name",
                                    name = "Extremely Long Local Model Name 32B",
                                    modelKind = MODEL_KIND_CHAT,
                                    capabilities = listOf("chat"),
                                    installed = true,
                                    source = "local",
                                )
                            ),
                            selected = false,
                            enabled = true,
                            onClick = {},
                            onRename = {},
                            onArchive = {},
                            onRestore = {},
                            onDelete = {},
                        )
                    }
                }
            }
        }

        languageTags.forEach { languageTag ->
            compose.runOnUiThread {
                currentLanguage.value = languageTag
            }
            compose.waitForIdle()

            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag, fontScale = 1.45f)
            val rootBounds = compose
                .onNodeWithTag(chatDrawerOverflowMenuNarrowRootTestTag)
                .getUnclippedBoundsInRoot()
            val optionsLabel = localizedContext.getString(R.string.chat_session_more_named, session.title)

            compose.onNodeWithTag(drawerChatRowOptionsTestTag(session.id), useUnmergedTree = true)
                .assert(hasContentDescription(optionsLabel) and hasClickActionLabel(optionsLabel))
                .performClick()
            compose.waitForIdle()

            val actionBounds = menuActions.map { actionExpectation ->
                val tag = drawerChatRowMenuItemTestTag(session.id, actionExpectation.action)
                val labelTag = drawerChatRowMenuItemLabelTestTag(session.id, actionExpectation.action)
                val label = localizedContext.getString(actionExpectation.labelRes)
                val namedLabel = localizedContext.getString(actionExpectation.namedLabelRes, session.title)
                val itemBounds = compose
                    .onNodeWithTag(tag, useUnmergedTree = true)
                    .assert(hasContentDescription(namedLabel) and hasClickActionLabel(namedLabel))
                    .getUnclippedBoundsInRoot()
                val labelBounds = compose
                    .onNodeWithTag(labelTag, useUnmergedTree = true)
                    .assertTextContains(label)
                    .getUnclippedBoundsInRoot()

                assertBoundsInside("$languageTag drawer overflow ${actionExpectation.action} item", itemBounds, rootBounds)
                assertBoundsInside("$languageTag drawer overflow ${actionExpectation.action} label", labelBounds, itemBounds)
                actionExpectation.action to itemBounds
            }

            actionBounds.zipWithNext().forEach { (current, next) ->
                assertFalse(
                    "$languageTag drawer overflow menu items ${current.first} and ${next.first} should not overlap.",
                    boundsOverlap(current.second, next.second),
                )
            }

            compose.onNodeWithTag(drawerChatRowMenuItemTestTag(session.id, "rename"), useUnmergedTree = true)
                .performClick()
            compose.waitForIdle()
        }
    }

    @Test
    fun chatScreenAcceptsInputAndSendWhenConnectedModelIsReady() {
        var sendClicks = 0
        var attachmentClicks = 0
        val hapticFeedback = RecordingHapticFeedback()
        val chatModel = RuntimeModel(
            id = "ollama:llama3.1:8b",
            name = "Llama 3.1 8B",
            modelKind = MODEL_KIND_CHAT,
            capabilities = listOf("chat"),
            installed = true,
            source = "local",
        )
        val state = mutableStateOf(
            RuntimeUiState(
                isConnected = true,
                runtimeStatus = "authenticated",
                trustedRuntime = RuntimeTrustedRuntime(
                    deviceId = "runtime-1",
                    name = "AetherLink Runtime",
                ),
                backendAvailable = true,
                selectedModelId = chatModel.id,
                models = listOf(chatModel),
                selectedTheme = RuntimeAppTheme.System,
            )
        )

        compose.setContent {
            CompositionLocalProvider(LocalHapticFeedback provides hapticFeedback) {
                MaterialTheme {
                    ChatScreen(
                        state = state.value,
                        onInputChange = { text -> state.value = state.value.copy(chatInput = text) },
                        onSend = { sendClicks += 1 },
                        onCancel = {},
                        onConnect = {},
                        onScanPairingQr = {},
                        onRefreshHealth = {},
                        onAttachFiles = { attachmentClicks += 1 },
                        onRemoveAttachment = {},
                        onScanLatestQr = {},
                    )
                }
            }
        }

        compose.onNodeWithContentDescription("Message")
            .assertIsDisplayed()
            .performTextInput("Hello")
        compose.onNodeWithContentDescription("Message")
            .performImeAction()
        compose.onNode(
            hasContentDescription("Attach files") and
                hasStateDescription("Ready to attach files.") and
                hasClickActionLabel("Attach files"),
        )
            .assertIsDisplayed()
            .assertIsEnabled()
            .performClick()
        compose.onNode(
            hasContentDescription("Send message") and
                hasClickActionLabel("Send message"),
        )
            .assertIsEnabled()
            .performClick()

        assertEquals("Hello", state.value.chatInput)
        assertEquals(1, attachmentClicks)
        assertEquals(2, sendClicks)
        assertEquals(
            listOf(
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
            ),
            hapticFeedback.events,
        )
    }

