                            pendingAttachments = pendingDocumentAttachments(attachmentCount.value),
                        ),
                        onInputChange = {},
                        onSend = {},
                        onCancel = {},
                        onConnect = {},
                        onScanPairingQr = {},
                        onRefreshHealth = {},
                        onAttachFiles = { attachClicks += 1 },
