    @Test
    fun chatScreenShortReasoningIsReadAsStaticThinkingAcrossSupportedLanguages() {
        val languageTags = listOf("en", "ko", "ja", "zh-CN", "fr")
        val chatModel = RuntimeModel(
            id = "ollama:reasoning",
            name = "Reasoning Model",
