                                onCancel = {},
                                onConnect = {},
                                onScanPairingQr = {},
                                onRefreshHealth = {},
                                onAttachFiles = {},
                                onRemoveAttachment = {},
                                onScanLatestQr = {},
                                modifier = Modifier.fillMaxSize(),
                            )
                        }
                    }
                }
            }
        }

        languageTags.forEach { nextLanguageTag ->
            compose.runOnUiThread { language.value = nextLanguageTag }
            compose.waitForIdle()

