                            onStopDiscovery = {},
                            onUseDiscoveredRuntime = {},
                            onForgetTrustedRuntime = {},
                            onScanPairingQr = { scanClicks += 1 },
                            onSubmitPairingPayload = {},
                            onConnect = {},
                            onRefreshHealth = {},
                            onRequestModels = {},
                            onDisconnect = {},
                            onSetAutoReconnectEnabled = {},
                            onSetLanguageTag = {},
                            onSetTheme = {},
