    @Test
    fun settingsMemoryRowsExposeContextualActionAccessibility() {
        val hapticFeedback = RecordingHapticFeedback()
        val toggledMemory = mutableListOf<Pair<String, Boolean>>()
        var removeClicks = 0
        val activeMemory = RuntimeMemoryEntry(
            id = "memory-active",
            content = "Project Alpha prefers concise Korean summaries",
            enabled = true,
            createdAtMillis = 1_000L,
            updatedAtMillis = 2_000L,
        )
        val pausedMemory = RuntimeMemoryEntry(
            id = "memory-paused",
            content = "Use metric units for travel planning",
            enabled = false,
            createdAtMillis = 3_000L,
            updatedAtMillis = 4_000L,
        )

        compose.setContent {
            MaterialTheme {
                CompositionLocalProvider(LocalHapticFeedback provides hapticFeedback) {
                    SettingsScreen(
                        state = RuntimeUiState(
                            isConnected = true,
                            runtimeStatus = "authenticated",
                            trustedRuntime = RuntimeTrustedRuntime(
                                deviceId = "runtime-1",
                                name = "AetherLink Runtime",
                            ),
                            memoryEntries = listOf(activeMemory, pausedMemory),
                        ),
                        onHostChange = {},
                        onPortChange = {},
                        onUseUsbReverse = {},
                        onUseEmulator = {},
                        onStartDiscovery = {},
                        onStopDiscovery = {},
                        onUseDiscoveredRuntime = {},
                        onForgetTrustedRuntime = {},
                        onScanPairingQr = {},
                        onSubmitPairingPayload = {},
                        onConnect = {},
                        onRefreshHealth = {},
                        onRequestModels = {},
                        onDisconnect = {},
                        onSetAutoReconnectEnabled = {},
                        onSetLanguageTag = {},
                        onSetTheme = {},
                        onSelectEmbeddingModel = {},
                        onAddMemoryEntry = {},
                        onRemoveMemoryEntry = {
                            removeClicks += 1
                        },
                        onSetMemoryEntryEnabled = { id, enabled ->
                            toggledMemory += id to enabled
                        },
                        onArchiveChatSession = {},
                        onRestoreChatSession = {},
                        onPermanentlyDeleteChatSession = {},
                        onArchiveAllChatSessions = {},
                        onPermanentlyDeleteArchivedChatSessions = {},
                        showDeveloperDiagnostics = false,
                    )
                }
            }
        }

        scrollUntilTextIsVisible("Memory")
        compose.onNodeWithText("Memory")
            .performScrollTo()
            .performClick()
        compose.waitForIdle()
        hapticFeedback.events.clear()

        compose.onNodeWithContentDescription(
            "Pause memory Project Alpha prefers concise Korean summaries",
            useUnmergedTree = true,
        )
            .performScrollTo()
            .assert(hasStateDescription("Enabled"))
            .assert(hasClickActionLabel("Pause memory Project Alpha prefers concise Korean summaries"))
            .performClick()
        assertEquals(listOf(HapticFeedbackType.TextHandleMove), hapticFeedback.events)
        compose.onNodeWithContentDescription(
            "Enable memory Use metric units for travel planning",
            useUnmergedTree = true,
        )
            .performScrollTo()
            .assert(hasStateDescription("Paused"))
            .assert(hasClickActionLabel("Enable memory Use metric units for travel planning"))
            .assertIsDisplayed()
        compose.onNodeWithContentDescription(
            "Remove memory Project Alpha prefers concise Korean summaries",
            useUnmergedTree = true,
        )
            .performScrollTo()
            .assert(hasClickActionLabel("Remove memory Project Alpha prefers concise Korean summaries"))
            .assertIsDisplayed()
            .performClick()
        compose.onNodeWithText("Remove memory?").assertIsDisplayed()
        compose.onNodeWithText(
            "Delete memory Project Alpha prefers concise Korean summaries from the trusted runtime?",
        ).assertIsDisplayed()
        compose.onNode(
            hasText("Delete") and
                hasContentDescription("Remove memory Project Alpha prefers concise Korean summaries") and
                hasClickActionLabel("Remove memory Project Alpha prefers concise Korean summaries"),
        ).assertIsDisplayed()
        compose.onNode(
            hasText("Cancel") and
                hasContentDescription("Cancel: Remove memory Project Alpha prefers concise Korean summaries") and
                hasClickActionLabel("Cancel: Remove memory Project Alpha prefers concise Korean summaries"),
        ).assertIsDisplayed()
        assertEquals(
            listOf(HapticFeedbackType.TextHandleMove, HapticFeedbackType.TextHandleMove),
            hapticFeedback.events,
        )
        compose.onNode(
            hasText("Cancel") and
                hasContentDescription("Cancel: Remove memory Project Alpha prefers concise Korean summaries"),
        ).performClick()
        assertEquals(
            listOf(
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
            ),
            hapticFeedback.events,
        )
        compose.onNodeWithContentDescription(
            "Remove memory Project Alpha prefers concise Korean summaries",
            useUnmergedTree = true,
        )
            .performScrollTo()
            .assertIsDisplayed()
            .performClick()
        compose.onNode(
            hasText("Delete") and
                hasContentDescription("Remove memory Project Alpha prefers concise Korean summaries") and
                hasClickActionLabel("Remove memory Project Alpha prefers concise Korean summaries"),
        ).assertIsDisplayed()
        compose.onNodeWithText("Delete").performClick()

        assertEquals(listOf("memory-active" to false), toggledMemory)
        assertEquals(1, removeClicks)
        assertEquals(
            listOf(
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.TextHandleMove,
                HapticFeedbackType.LongPress,
            ),
            hapticFeedback.events,
        )
    }

    @Test
    fun settingsMemoryDeleteConfirmationDialogStaysBoundedAtLargeFontAcrossSupportedLanguages() {
        val languageTags = listOf("en", "ko", "ja", "zh-CN", "fr")
        val currentLanguage = mutableStateOf(languageTags.first())
        val fontScale = 1.5f
        val memoryContent = "Project Alpha prefers concise Korean summaries with metric travel planning notes"
        val entry = RuntimeMemoryEntry(
            id = "memory-active",
            content = memoryContent,
            enabled = true,
            createdAtMillis = 1_000L,
            updatedAtMillis = 2_000L,
        )

        compose.setContent {
            MaterialTheme {
                LocalizedTestContent(languageTag = currentLanguage.value, fontScale = fontScale) {
                    key(currentLanguage.value) {
                        Surface(
                            modifier = Modifier
                                .width(320.dp)
                                .height(560.dp),
                        ) {
                            MemoryEntryRow(
                                entry = entry,
                                actionsEnabled = true,
                                disabledActionStateDescription = null,
                                onRemoveMemoryEntry = {},
                                onSetMemoryEntryEnabled = { _, _ -> },
                            )
                        }
                    }
                }
            }
        }

        languageTags.forEach { languageTag ->
            compose.runOnUiThread {
                currentLanguage.value = languageTag
            }
            compose.waitForIdle()

            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag, fontScale = fontScale)
            val memoryActionLabel = if (memoryContent.length <= MEMORY_ACTION_LABEL_MAX_CHARS) {
                memoryContent
            } else {
                memoryContent.take(MEMORY_ACTION_LABEL_MAX_CHARS).trimEnd() + "..."
            }
            val removeAction = localizedContext.getString(R.string.memory_remove_named, memoryActionLabel)
            val cancelAction = localizedContext.getString(R.string.confirmation_cancel_action_named, removeAction)

            compose.onNode(
                hasContentDescription(removeAction) and hasClickActionLabel(removeAction),
                useUnmergedTree = true,
            )
                .assertIsDisplayed()
                .performClick()
            compose.waitForIdle()

            val dialogBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_DIALOG_TEST_TAG, useUnmergedTree = true)
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()
            val titleBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_TITLE_TEST_TAG, useUnmergedTree = true)
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()
            val messageBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_MESSAGE_TEST_TAG, useUnmergedTree = true)
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()
            val confirmBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_CONFIRM_TEST_TAG, useUnmergedTree = true)
                .assert(hasContentDescription(removeAction) and hasClickActionLabel(removeAction))
                .assertIsEnabled()
                .getUnclippedBoundsInRoot()
            val confirmLabelBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_CONFIRM_LABEL_TEST_TAG, useUnmergedTree = true)
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()
            val cancelBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_CANCEL_TEST_TAG, useUnmergedTree = true)
                .assert(hasContentDescription(cancelAction) and hasClickActionLabel(cancelAction))
                .assertIsEnabled()
                .getUnclippedBoundsInRoot()
            val cancelLabelBounds = compose
                .onNodeWithTag(MEMORY_DELETE_CONFIRMATION_CANCEL_LABEL_TEST_TAG, useUnmergedTree = true)
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()

            assertTrue(
                "$languageTag memory delete confirmation dialog should stay compact. bounds=$dialogBounds",
                dialogBounds.right - dialogBounds.left <= 360.dp,
            )
            assertBoundsInside("$languageTag memory delete confirmation title", titleBounds, dialogBounds)
            assertBoundsInside("$languageTag memory delete confirmation message", messageBounds, dialogBounds)
            assertBoundsInside("$languageTag memory delete confirmation confirm action", confirmBounds, dialogBounds)
            assertBoundsInside(
                "$languageTag memory delete confirmation confirm label",
                confirmLabelBounds,
                confirmBounds,
            )
            assertBoundsInside("$languageTag memory delete confirmation cancel action", cancelBounds, dialogBounds)
            assertBoundsInside(
                "$languageTag memory delete confirmation cancel label",
                cancelLabelBounds,
                cancelBounds,
            )
            assertFalse(
                "$languageTag memory delete confirmation actions should not overlap.",
                boundsOverlap(confirmBounds, cancelBounds),
            )

            compose.onNodeWithTag(MEMORY_DELETE_CONFIRMATION_CANCEL_TEST_TAG, useUnmergedTree = true)
                .performClick()
            compose.waitForIdle()
        }
    }

