                .getUnclippedBoundsInRoot()
            val toggleLabelBounds = compose
                .onNodeWithTag(MEMORY_ENTRY_SOURCE_TOGGLE_LABEL_TEST_TAG, useUnmergedTree = true)
                .assertTextContains(showSource)
                .getUnclippedBoundsInRoot()
