                LocalizedTestContent(languageTag = expected.languageTag) {
                    key(expected.languageTag, expected.connected, expected.streaming) {
                        SettingsScreen(
                            state = RuntimeUiState(
                                isConnected = expected.connected,
                                isStreaming = expected.streaming,
