        )
        val runningChatModel = RuntimeModel(
            id = "lmstudio:llama-running-local-runtime-chat-model",
            name = "Llama Running Local Runtime Chat Model",
            modelKind = MODEL_KIND_CHAT,
            capabilities = listOf("chat"),
            installed = true,
            running = true,
            provider = "lm_studio",
            source = "local",
        )
        val uninstalledChatModel = RuntimeModel(
            id = "ollama:gemma-uninstalled-vision-candidate",
            name = "Gemma Uninstalled Vision Candidate Model",
            modelKind = MODEL_KIND_CHAT,
            capabilities = listOf("chat"),
            installed = false,
            source = "local",
        )
        val currentLanguageTag = mutableStateOf(languageTags.first())

        compose.setContent {
            MaterialTheme {
                LocalizedTestContent(languageTag = currentLanguageTag.value, fontScale = 1.45f) {
                    key(currentLanguageTag.value) {
                        Surface(
                            modifier = Modifier
                                .width(320.dp)
                                .height(640.dp)
                                .testTag(chatModelRowsNarrowRootTestTag),
                        ) {
                            ChatTopAppBarTitle(
                                state = RuntimeUiState(
                                    isConnected = true,
                                    runtimeStatus = "authenticated",
                                    backendAvailable = true,
                                    selectedModelId = selectedChatModel.id,
                                    models = listOf(
                                        selectedChatModel,
                                        runningChatModel,
                                        uninstalledChatModel,
                                    ),
                                ),
                                onRequestModels = {},
                                onSelectModel = {},
                            )
                        }
                    }
                }
            }
        }

        fun statusLine(context: Context, model: RuntimeModel): String {
            val providerName = when (model.provider) {
                "lm_studio", "lmstudio" -> context.getString(R.string.provider_lm_studio)
                else -> context.getString(R.string.provider_ollama)
            }
            val availability = when {
                !model.installed -> context.getString(R.string.model_not_installed)
                model.running -> context.getString(R.string.model_running)
                else -> context.getString(R.string.model_installed)
            }
            return context.getString(R.string.model_status_value, providerName, availability)
        }

        fun assertModelRowBounds(languageTag: String, model: RuntimeModel) {
            val rowTag = chatModelMenuItemTestTag(model.id)
            val rootBounds = compose.onNodeWithTag(chatModelRowsNarrowRootTestTag)
                .getUnclippedBoundsInRoot()
            val rowBounds = compose.onNodeWithTag(rowTag, useUnmergedTree = true)
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()
            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag, fontScale = 1.45f)
            val statusText = statusLine(localizedContext, model)
            val nameBounds = compose.onNode(
                hasText(model.name) and hasAnyAncestor(hasTestTag(rowTag)),
                useUnmergedTree = true,
            )
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()
            val statusBounds = compose.onNode(
                hasText(statusText) and hasAnyAncestor(hasTestTag(rowTag)),
                useUnmergedTree = true,
            )
                .assertIsDisplayed()
                .getUnclippedBoundsInRoot()

            assertBoundsInside("$languageTag model picker row ${model.id}", rowBounds, rootBounds)
            assertBoundsInside("$languageTag model picker row name ${model.id}", nameBounds, rowBounds)
            assertBoundsInside("$languageTag model picker row status ${model.id}", statusBounds, rowBounds)
            assertFalse(
                "$languageTag model picker name and status should stack without overlapping for ${model.id}.",
                boundsOverlap(nameBounds, statusBounds),
            )

            if (!model.installed) {
                val installLabel = localizedContext.getString(R.string.install_model)
                val installBounds = compose.onNode(
                    hasText(installLabel) and hasAnyAncestor(hasTestTag(rowTag)),
                    useUnmergedTree = true,
                )
                    .assertIsDisplayed()
                    .getUnclippedBoundsInRoot()
                assertBoundsInside(
                    "$languageTag model picker install action ${model.id}",
                    installBounds,
                    rowBounds,
                )
                assertFalse(
                    "$languageTag model picker install action should not overlap status for ${model.id}.",
                    boundsOverlap(installBounds, statusBounds),
                )
            }
        }

        languageTags.forEach { languageTag ->
            compose.runOnUiThread {
                currentLanguageTag.value = languageTag
            }
            compose.waitForIdle()

            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag, fontScale = 1.45f)
            val selectedSummary = localizedContext.getString(
                R.string.chat_model_picker_summary_selected,
                selectedChatModel.name,
            )
            compose.onNodeWithContentDescription(selectedSummary)
                .assertIsDisplayed()
                .performClick()
            compose.waitForIdle()

            assertModelRowBounds(languageTag, selectedChatModel)
            assertModelRowBounds(languageTag, runningChatModel)
            assertModelRowBounds(languageTag, uninstalledChatModel)
        }
    }

    @Test
    fun chatTopBarModelPickerGuidesImageAttachmentVisionRecoveryAcrossSupportedLanguages() {
        data class ExpectedVisionRecoveryCopy(
            val languageTag: String,
            val recoveryState: String,
            val recoveryDetail: String,
            val blockedState: String,
            val blockedAction: String,
            val chooseModelLabel: String,
        )

        val expectedCopies = listOf(
            ExpectedVisionRecoveryCopy(
                languageTag = "en",
                recoveryState = "Vision-capable AetherLink Runtime chat model required.",
                recoveryDetail = "This image needs a vision-capable AetherLink Runtime chat model. Choose an installed vision model from AetherLink Runtime.",
                blockedState = "Vision model required for image attachments.",
                blockedAction = "Not recommended for images",
                chooseModelLabel = "Choose model",
            ),
            ExpectedVisionRecoveryCopy(
                languageTag = "ko",
                recoveryState = "비전 지원 AetherLink Runtime 채팅 모델이 필요합니다.",
                recoveryDetail = "이 이미지는 비전 지원 AetherLink Runtime 채팅 모델이 필요합니다. AetherLink Runtime에서 설치된 비전 모델을 선택하세요.",
                blockedState = "이미지 첨부에는 비전 모델이 필요합니다.",
                blockedAction = "이미지에는 권장되지 않음",
                chooseModelLabel = "모델 선택",
            ),
            ExpectedVisionRecoveryCopy(
                languageTag = "ja",
                recoveryState = "ビジョン対応の AetherLink Runtime チャットモデルが必要です。",
                recoveryDetail = "この画像には、ビジョン対応の AetherLink Runtime チャットモデルが必要です。AetherLink Runtime のインストール済みビジョンモデルを選択してください。",
                blockedState = "画像添付にはビジョンモデルが必要です。",
                blockedAction = "画像には推奨されません",
                chooseModelLabel = "モデルを選択",
            ),
            ExpectedVisionRecoveryCopy(
                languageTag = "zh-CN",
                recoveryState = "需要支持视觉的 AetherLink Runtime 聊天模型。",
                recoveryDetail = "此图片需要支持视觉的 AetherLink Runtime 聊天模型。请从 AetherLink Runtime 选择已安装的视觉模型。",
                blockedState = "图片附件需要视觉模型。",
                blockedAction = "不建议用于图片",
                chooseModelLabel = "选择模型",
            ),
            ExpectedVisionRecoveryCopy(
                languageTag = "fr",
                recoveryState = "Modèle de chat AetherLink Runtime compatible vision requis.",
                recoveryDetail = "Cette image nécessite un modèle de chat AetherLink Runtime compatible vision. Choisissez un modèle vision installé depuis AetherLink Runtime.",
                blockedState = "Un modèle vision est requis pour les images jointes.",
                blockedAction = "Non recommandé pour les images",
                chooseModelLabel = "Choisir un modèle",
            ),
        )
        val currentCopy = mutableStateOf(expectedCopies.first())
        val selectedChatModelIds = mutableListOf<String>()
        val hapticFeedback = RecordingHapticFeedback()
        val textChatModel = RuntimeModel(
            id = "ollama:qwen3:8b",
            name = "Qwen3 8B",
            modelKind = MODEL_KIND_CHAT,
            capabilities = listOf("chat"),
            installed = true,
            source = "local",
        )
        val visionChatModel = RuntimeModel(
            id = "ollama:llava:13b",
            name = "Llava 13B",
            modelKind = MODEL_KIND_CHAT,
            capabilities = listOf("chat", "vision"),
            installed = true,
            source = "local",
        )
        val imageAttachment = RuntimePendingAttachment(
            id = "attachment-image",
            type = "image",
            name = "diagram.png",
            mimeType = "image/png",
            sizeBytes = 12_000L,
            dataBase64 = "aW1hZ2U=",
        )
        fun visionModelSummary(languageTag: String): String {
            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag)
            return localizedContext.getString(
                R.string.chat_model_row_summary,
                visionChatModel.name,
                localizedContext.getString(
                    R.string.model_status_value,
                    "Ollama",
                    localizedContext.getString(R.string.model_installed),
                ),
            )
        }
        fun textModelBlockedStatusLine(languageTag: String): String {
            val localizedContext = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(languageTag)
            return localizedContext.getString(
                R.string.model_status_value,
                "Ollama",
                localizedContext.getString(R.string.model_not_recommended_for_images),
            )
        }

        expectedCopies.forEach { expected ->
            val context = ApplicationProvider
                .getApplicationContext<Context>()
                .localizedContext(expected.languageTag)
            assertEquals(expected.recoveryState, context.getString(R.string.model_picker_vision_recovery_state))
            assertEquals(expected.recoveryDetail, context.getString(R.string.model_picker_vision_recovery_detail))
            assertEquals(expected.blockedState, context.getString(R.string.model_picker_vision_model_required_state))
            assertEquals(expected.blockedAction, context.getString(R.string.model_not_recommended_for_images))
        }

        compose.setContent {
            MaterialTheme {
                val expected = currentCopy.value
                LocalizedTestContent(languageTag = expected.languageTag) {
                    key(expected.languageTag) {
                        CompositionLocalProvider(LocalHapticFeedback provides hapticFeedback) {
                            Column(modifier = Modifier.width(360.dp).height(640.dp)) {
                                ChatTopAppBarTitle(
                                    state = RuntimeUiState(
                                        isConnected = true,
                                        runtimeStatus = "authenticated",
                                        backendAvailable = true,
                                        selectedModelId = textChatModel.id,
                                        models = listOf(textChatModel, visionChatModel),
                                        pendingAttachments = listOf(imageAttachment),
                                    ),
                                    onRequestModels = {},
                                    onSelectModel = { selectedChatModelIds += it },
                                )
                            }
                        }
                    }
                }
            }
        }

        expectedCopies.forEach { expected ->
            compose.runOnUiThread {
                currentCopy.value = expected
            }
            compose.waitForIdle()

            compose.onNode(
                hasText("Qwen3 8B") and
                    hasStateDescription(expected.recoveryState) and
                    hasClickActionLabel(expected.chooseModelLabel),
            )
                .assertIsDisplayed()
                .assertIsEnabled()
            if (expected.languageTag != "en") return@forEach

            compose.onNode(
                hasText("Qwen3 8B") and
                    hasStateDescription(expected.recoveryState) and
                    hasClickActionLabel(expected.chooseModelLabel),
            ).performClick()
            compose.waitForIdle()
            compose.onNodeWithText(expected.recoveryDetail, useUnmergedTree = true)
                .assertIsDisplayed()
            compose.onNode(
                hasContentDescription(expected.recoveryDetail) and hasPoliteLiveRegion(),
                useUnmergedTree = true,
            ).assertExists()
            compose.onNode(
                hasText("Qwen3 8B") and
                    hasStateDescription(expected.blockedState),
            )
                .assertExists()
                .assertIsNotEnabled()
            compose.onNodeWithText(textModelBlockedStatusLine(expected.languageTag), useUnmergedTree = true)
                .assertIsDisplayed()
            compose.onNode(
                hasContentDescription(visionModelSummary(expected.languageTag)) and
                    hasClickActionLabel(expected.chooseModelLabel),
            )
                .assertExists()
                .assertIsDisplayed()
                .assertIsEnabled()
            hapticFeedback.events.clear()
            compose.onNode(
                hasContentDescription(visionModelSummary(expected.languageTag)) and
                    hasClickActionLabel(expected.chooseModelLabel),
            ).performClick()
            compose.waitForIdle()
        }

        assertEquals(listOf(visionChatModel.id), selectedChatModelIds)
        assertEquals(listOf(HapticFeedbackType.TextHandleMove), hapticFeedback.events)
    }

    @Test
